fn testExchangeFingerprint(domain: []const u8, version: u32, image_bytes: []const u8) u64 {
    var hasher = std.hash.Wyhash.init(0);
    testHashBytes(&hasher, domain);
    testHashU32(&hasher, version);
    testHashBytes(&hasher, image_bytes);
    return hasher.final();
}

fn testLegacyProgramProviderOfferBytes(comptime Program: type, allocator: std.mem.Allocator, offer: Program.Exchange.ProviderOffer) ![]u8 {
    const program_ref = offer.provider_program_ref orelse return error.ExpectedProviderProgramRef;
    const payload = offer.bytes[0 .. offer.bytes.len - 8];
    const program_label_len: usize = if (program_ref.label) |label| @sizeOf(u64) + label.len else 0;
    const program_ref_len = @sizeOf(u64) + @sizeOf(u8) + program_label_len;
    const request_mapping_len = @sizeOf(u64) + @tagName(offer.provider_program_request_mapping orelse return error.ExpectedProviderProgramRef).len;
    const result_mapping_len = @sizeOf(u64) + @tagName(offer.provider_program_result_mapping orelse return error.ExpectedProviderProgramRef).len;
    const current_only_tail_len = program_ref_len + request_mapping_len + result_mapping_len + @sizeOf(u64) + @sizeOf(u64);
    if (payload.len <= current_only_tail_len) return error.ProgramContractViolation;
    const legacy_payload_len = payload.len - current_only_tail_len;
    var legacy = try allocator.alloc(u8, legacy_payload_len + @sizeOf(u64));
    errdefer allocator.free(legacy);
    @memcpy(legacy[0..legacy_payload_len], payload[0..legacy_payload_len]);
    std.mem.writeInt(u32, legacy["ABL_EXO1".len..][0..4], 2, .little);
    const fingerprint = testExchangeFingerprint(
        "boundary.exchange.provider_offer",
        Program.Exchange.provider_offer_fingerprint_version,
        legacy[0..legacy_payload_len],
    );
    std.mem.writeInt(u64, legacy[legacy_payload_len..][0..8], fingerprint, .little);
    return legacy;
}

fn testHashOptionalU64(hasher: *std.hash.Wyhash, value: ?u64) void {
    hasher.update(&[_]u8{@intFromBool(value != null)});
    if (value) |actual| testHashU64(hasher, actual);
}

fn testHashBool(hasher: *std.hash.Wyhash, value: bool) void {
    hasher.update(&[_]u8{@intFromBool(value)});
}

fn testHashU64List(hasher: *std.hash.Wyhash, values: []const u64) void {
    testHashUsize(hasher, values.len);
    for (values) |value| testHashU64(hasher, value);
}

fn testHashStringList(hasher: *std.hash.Wyhash, values: []const []const u8) void {
    testHashUsize(hasher, values.len);
    for (values) |value| testHashBytes(hasher, value);
}

fn testHashValueRef(hasher: *std.hash.Wyhash, ref: boundary.ir.ValueRef) void {
    testHashBytes(hasher, @tagName(ref.codec));
    if (ref.schema_index) |schema_index| {
        testHashU32(hasher, schema_index);
    } else {
        testHashBytes(hasher, "none");
    }
}

fn testHashValueRefList(hasher: *std.hash.Wyhash, values: []const boundary.ir.ValueRef) void {
    testHashUsize(hasher, values.len);
    for (values) |value| testHashValueRef(hasher, value);
}

fn testWriteU32(bytes: *std.ArrayList(u8), allocator: std.mem.Allocator, value: u32) !void {
    var buffer: [4]u8 = undefined;
    std.mem.writeInt(u32, &buffer, value, .little);
    try bytes.appendSlice(allocator, &buffer);
}

fn testWriteU64(bytes: *std.ArrayList(u8), allocator: std.mem.Allocator, value: u64) !void {
    var buffer: [8]u8 = undefined;
    std.mem.writeInt(u64, &buffer, value, .little);
    try bytes.appendSlice(allocator, &buffer);
}

fn testWriteOptionalU64(bytes: *std.ArrayList(u8), allocator: std.mem.Allocator, value: ?u64) !void {
    try bytes.append(allocator, @intFromBool(value != null));
    if (value) |actual| try testWriteU64(bytes, allocator, actual);
}

fn testUsageTag(comptime Program: type, value: Program.Exchange.Usage) u8 {
    return switch (value) {
        .copyable => 0,
        .replayable => 1,
        .affine => 2,
        .linear => 3,
        .ephemeral => 4,
    };
}

fn testResponseUseTag(comptime Program: type, value: Program.Exchange.ResponseUse) u8 {
    return switch (value) {
        .fresh => 0,
        .replayed => 1,
        .deterministic_replay => 2,
        .override => 3,
    };
}

fn testBranchPolicyTag(comptime Program: type, value: Program.Exchange.BranchPolicy) u8 {
    return switch (value) {
        .unrestricted => 0,
        .replay_only => 1,
        .single_live_branch => 2,
        .split_required => 3,
        .no_branch => 4,
        .host_owned => 5,
    };
}

fn testTreatyCoreV2Fingerprint(comptime Program: type, treaty: Program.Exchange.Treaty) u64 {
    var hasher = std.hash.Wyhash.init(0);
    testHashBytes(&hasher, "boundary.exchange.treaty");
    testHashU32(&hasher, 2);
    testHashU64(&hasher, treaty.request_envelope_fingerprint);
    testHashU64(&hasher, treaty.request_fingerprint);
    testHashU64(&hasher, treaty.manifest_fingerprint);
    testHashU64(&hasher, treaty.provider_fingerprint);
    testHashU64(&hasher, treaty.provider_offer_fingerprint);
    testHashStringList(&hasher, treaty.provider_offer_tags);
    testHashU64(&hasher, treaty.capability_fingerprint);
    testHashU64(&hasher, treaty.capability_path_fingerprint);
    testHashOptionalU64(&hasher, treaty.capability_instance_fingerprint);
    testHashOptionalU64(&hasher, treaty.obligation_fingerprint);
    testHashU64(&hasher, treaty.route.fingerprint);
    testHashBytes(&hasher, @tagName(treaty.handling));
    testHashU64List(&hasher, treaty.morphism_offer_fingerprints);
    testHashOptionalU64(&hasher, treaty.effect_session_spec_fingerprint);
    testHashU64List(&hasher, treaty.dynamic_morphism_fingerprints);
    testHashU64List(&hasher, treaty.residualization_fingerprints);
    testHashOptionalU64(&hasher, treaty.pipeline_fingerprint);
    testHashOptionalU64(&hasher, treaty.source_protocol_op_fingerprint);
    testHashOptionalU64(&hasher, treaty.target_protocol_op_fingerprint);
    testHashBytes(&hasher, @tagName(treaty.usage));
    testHashBytes(&hasher, @tagName(treaty.provider_usage));
    testHashBytes(&hasher, @tagName(treaty.response_use));
    testHashBytes(&hasher, @tagName(treaty.replay_policy));
    testHashBytes(&hasher, @tagName(treaty.branch_policy));
    testHashBool(&hasher, treaty.expected_response_kinds.@"resume");
    testHashBool(&hasher, treaty.expected_response_kinds.return_now);
    testHashBool(&hasher, treaty.expected_response_kinds.resume_after);
    testHashValueRefList(&hasher, treaty.expected_response_refs);
    testHashValueRefList(&hasher, treaty.provider_response_refs);
    testHashOptionalU64(&hasher, treaty.journal_policy_fingerprint);
    testHashBool(&hasher, treaty.require_treaty_bound_response_authorization);
    return hasher.final();
}

