    try testWriteU64(&bytes, allocator, testTreatyAuthorizationV3Fingerprint(Program, authorization));
    return bytes.toOwnedSlice(allocator);
}

fn expectFirstTreatyBlocker(comptime Program: type, report: Program.Exchange.Treaty.BlockerList, expected: Program.Exchange.Treaty.BlockerTag) !void {
    try std.testing.expect(!report.allowed());
    try std.testing.expect(report.count > 0);
    try std.testing.expectEqual(expected, report.blockers[0].tag);
}

const TestImageCursor = struct {
    bytes: []const u8,
    index: usize = 0,

    fn skip(self: *@This(), len: usize) !void {
        const end = std.math.add(usize, self.index, len) catch return error.ProgramContractViolation;
        if (end > self.bytes.len) return error.ProgramContractViolation;
        self.index = end;
    }

    fn readU8(self: *@This()) !u8 {
        if (self.index >= self.bytes.len) return error.ProgramContractViolation;
        const value = self.bytes[self.index];
        self.index += 1;
        return value;
    }

    fn readU16(self: *@This()) !u16 {
        if (self.index + 2 > self.bytes.len) return error.ProgramContractViolation;
        const value = std.mem.readInt(u16, self.bytes[self.index..][0..2], .little);
        self.index += 2;
        return value;
    }

    fn readUsize(self: *@This()) !usize {
        if (self.index + 8 > self.bytes.len) return error.ProgramContractViolation;
        const value = std.mem.readInt(u64, self.bytes[self.index..][0..8], .little);
        self.index += 8;
        return @intCast(value);
    }

    fn skipLenBytes(self: *@This()) !void {
        try self.skip(try self.readUsize());
    }

    fn skipUsizeList(self: *@This()) !void {
        const count = try self.readUsize();
        for (0..count) |_| try self.skip(8);
    }

    fn skipU64List(self: *@This()) !void {
        const count = try self.readUsize();
        for (0..count) |_| try self.skip(8);
    }

    fn skipStringList(self: *@This()) !void {
        const count = try self.readUsize();
        for (0..count) |_| try self.skipLenBytes();
    }

    fn skipOptionalUsize(self: *@This()) !void {
        if (try self.readU8() != 0) try self.skip(8);
    }

    fn readValueCodec(self: *@This()) !boundary.ir.ValueCodec {
        return switch (try self.readU8()) {
            @intFromEnum(boundary.ir.ValueCodec.unit) => .unit,
            @intFromEnum(boundary.ir.ValueCodec.bool) => .bool,
            @intFromEnum(boundary.ir.ValueCodec.i32) => .i32,
            @intFromEnum(boundary.ir.ValueCodec.product) => .product,
            @intFromEnum(boundary.ir.ValueCodec.usize) => .usize,
            @intFromEnum(boundary.ir.ValueCodec.string) => .string,
            @intFromEnum(boundary.ir.ValueCodec.string_list) => .string_list,
            @intFromEnum(boundary.ir.ValueCodec.sum) => .sum,
            else => error.ProgramContractViolation,
        };
    }

    fn skipValueRef(self: *@This()) !void {
        _ = try self.readValueCodec();
        if (try self.readU8() != 0) try self.skip(2);
    }

    fn skipValueRefList(self: *@This()) !void {
        const count = try self.readUsize();
        for (0..count) |_| try self.skipValueRef();
    }

    fn readValueRefCodec(self: *@This()) !boundary.ir.ValueCodec {
        const codec = try self.readValueCodec();
        if (try self.readU8() != 0) try self.skip(2);
        return codec;
    }

    fn skipValueForCodec(self: *@This(), codec: boundary.ir.ValueCodec) !void {
        switch (codec) {
            .unit => {},
            .bool => try self.skip(1),
            .i32 => try self.skip(4),
            .usize => try self.skip(8),
            .string => switch (try self.readU8()) {
                0 => try self.skipLenBytes(),
                1 => try self.skip(8),
                else => return error.ProgramContractViolation,
            },
            .string_list => switch (try self.readU8()) {
                0 => {
                    const item_count = try self.readUsize();
                    for (0..item_count) |_| switch (try self.readU8()) {
                        0 => try self.skipLenBytes(),
                        1 => try self.skip(8),
                        else => return error.ProgramContractViolation,
                    };
                },
                1 => try self.skip(8),
                else => return error.ProgramContractViolation,
            },
            .product, .sum => return error.ProgramContractViolation,
        }
    }

    fn skipMaybeValueForCodec(self: *@This(), codec: boundary.ir.ValueCodec) !void {
        if (try self.readU8() != 0) try self.skipValueForCodec(codec);
    }

    fn skipImageValueForCodec(self: *@This(), codec: boundary.ir.ValueCodec) !void {
        switch (try self.readU8()) {
            0 => try self.skipValueForCodec(codec),
            1 => try self.skip(8),
            else => return error.ProgramContractViolation,
        }
    }

    fn skipMaybeImageValueForCodec(self: *@This(), codec: boundary.ir.ValueCodec) !void {
        switch (try self.readU8()) {
            0 => {},
            1 => try self.skipValueForCodec(codec),
            2 => try self.skip(8),
            else => return error.ProgramContractViolation,
        }
    }
};

fn firstCapsuleFrameAfterStartOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    try cursor.skip("ABL_CAP1".len);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipLenBytes();
    try cursor.skipLenBytes();
    try cursor.skip(8);
    try cursor.skip(4);
    try cursor.skip(1);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skipValueRef();
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skip(2);
    try cursor.skip(8);

    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    const after_stack_len = try cursor.readUsize();
    try cursor.skip(after_stack_len * 6);
    const frame_count = try cursor.readUsize();
    if (frame_count == 0) return error.ProgramContractViolation;
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    return cursor.index;
}

fn firstCapsuleFrameWaitingFlagOffset(image_bytes: []const u8) !usize {
    const after_start_offset = try firstCapsuleFrameAfterStartOffset(image_bytes);
    return after_start_offset + 8 + 1;
}

fn capsuleCoreFrameCountOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsuleCoreRemainingStepsOffset(image_bytes);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    const after_stack_len = try cursor.readUsize();
    try cursor.skip(after_stack_len * 6);
    return cursor.index;
}

fn capsuleCoreRemainingStepsOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    try cursor.skip("ABL_CAP1".len);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipLenBytes();
    try cursor.skipLenBytes();
    try cursor.skip(8);
    try cursor.skip(4);
    try cursor.skip(1);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skipValueRef();
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skipOptionalUsize();
    try cursor.skip(2);
    try cursor.skip(8);
    return cursor.index;
}

fn capsuleCoreDoneConsumedOffset(image_bytes: []const u8) !usize {
    return (try capsuleCoreRemainingStepsOffset(image_bytes)) + 16;
}

fn firstCapsuleAfterStackAfterSiteOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsuleCoreRemainingStepsOffset(image_bytes);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    const after_stack_len = try cursor.readUsize();
    if (after_stack_len == 0) return error.ProgramContractViolation;
    try cursor.skip(2);
    try cursor.skip(2);
    return cursor.index;
}

fn pendingOpDstOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsuleCoreRemainingStepsOffset(image_bytes);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    const after_stack_len = try cursor.readUsize();
    try cursor.skip(after_stack_len * 6);
    const frame_count = try cursor.readUsize();
    if (frame_count != 1) return error.ProgramContractViolation;
    try cursor.skip(8 * 6);
    try cursor.skip(1);
    if (try cursor.readU8() != 0) try cursor.skip(2);
    const local_count = try cursor.readUsize();
    for (0..local_count) |_| {
        const codec = try cursor.readValueRefCodec();
        try cursor.skipMaybeImageValueForCodec(codec);
    }
    if (try cursor.readU8() != 0) return error.ProgramContractViolation;
    if (try cursor.readU8() == 0) return error.ProgramContractViolation;
    if (try cursor.readU8() != 0) return error.ProgramContractViolation;
    try cursor.skip(8 * 3);
    return cursor.index;
}

fn pendingOpAfterEntryOperationSiteOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsulePendingOffset(image_bytes);
    if (try cursor.readU8() == 0) return error.ProgramContractViolation;
    if (try cursor.readU8() != 0) return error.ProgramContractViolation;
    try cursor.skip(8 * 3);
    try cursor.skip(2);
    try cursor.skip(2);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    const payload_codec = try cursor.readValueRefCodec();
    try cursor.skip(2);
    try cursor.skipImageValueForCodec(payload_codec);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    try cursor.skipValueRef();
    try cursor.skipValueRef();
    if (try cursor.readU8() == 0) return error.ProgramContractViolation;
    try cursor.skip(2);
    return cursor.index;
}

fn capsulePendingOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsuleCoreRemainingStepsOffset(image_bytes);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    const after_stack_len = try cursor.readUsize();
    try cursor.skip(after_stack_len * 6);
    const frame_count = try cursor.readUsize();
    for (0..frame_count) |_| {
        try cursor.skip(8 * 6);
        try cursor.skip(1);
        if (try cursor.readU8() != 0) try cursor.skip(2);
        const local_count = try cursor.readUsize();
        for (0..local_count) |_| {
            const codec = try cursor.readValueRefCodec();
            try cursor.skipMaybeImageValueForCodec(codec);
        }
        switch (try cursor.readU8()) {
            0 => {},
            1 => try cursor.skip(4),
            2 => try cursor.skip(2),
            else => return error.ProgramContractViolation,
        }
    }
    return cursor.index;
}

fn capsuleFrameLocalImageOffset(image_bytes: []const u8, target_frame: usize, target_local: usize) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsuleCoreRemainingStepsOffset(image_bytes);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(1);
    const after_stack_len = try cursor.readUsize();
    try cursor.skip(after_stack_len * 6);
    const frame_count = try cursor.readUsize();
    if (target_frame >= frame_count) return error.ProgramContractViolation;
    for (0..frame_count) |frame_index| {
        try cursor.skip(8 * 6);
        try cursor.skip(1);
        if (try cursor.readU8() != 0) try cursor.skip(2);
        const local_count = try cursor.readUsize();
        if (frame_index == target_frame and target_local >= local_count) return error.ProgramContractViolation;
        for (0..local_count) |local_index| {
            const codec = try cursor.readValueRefCodec();
            const value_offset = cursor.index;
            if (frame_index == target_frame and local_index == target_local) return value_offset;
            try cursor.skipMaybeImageValueForCodec(codec);
        }
        switch (try cursor.readU8()) {
            0 => {},
            1 => try cursor.skip(4),
            2 => try cursor.skip(8),
            else => return error.ProgramContractViolation,
        }
    }
    return error.ProgramContractViolation;
}

fn pendingAfterRemainingOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsulePendingOffset(image_bytes);
    if (try cursor.readU8() == 0) return error.ProgramContractViolation;
    if (try cursor.readU8() != 1) return error.ProgramContractViolation;
    try cursor.skip(8 * 3);
    try cursor.skip(2);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    const value_codec = try cursor.readValueRefCodec();
    try cursor.skipImageValueForCodec(value_codec);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skipValueRef();
    try cursor.skipValueRef();
    return cursor.index;
}

fn pendingAfterOutputRefOffset(image_bytes: []const u8) !usize {
    var cursor = TestImageCursor{ .bytes = image_bytes };
    cursor.index = try capsulePendingOffset(image_bytes);
    if (try cursor.readU8() == 0) return error.ProgramContractViolation;
    if (try cursor.readU8() != 1) return error.ProgramContractViolation;
    try cursor.skip(8 * 3);
    try cursor.skip(2);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    try cursor.skip(8);
    const value_codec = try cursor.readValueRefCodec();
    try cursor.skipImageValueForCodec(value_codec);
    try cursor.skip(8);
    try cursor.skip(8);
    return cursor.index;
}

fn corruptLastU64Occurrence(image_bytes: []u8, value: u64) !void {
    var encoded = [_]u8{0} ** 8;
    std.mem.writeInt(u64, &encoded, value, .little);
    const payload = image_bytes[0 .. image_bytes.len - 8];
    var offset: ?usize = null;
    var index: usize = 0;
    while (std.mem.findPos(u8, payload, index, &encoded)) |found| {
        offset = found;
        index = found + 1;
    }
    const found_offset = offset orelse return error.ProgramContractViolation;
    image_bytes[found_offset] ^= 0x01;
}

fn rewriteCapsuleImageChecksum(comptime Program: type, image_bytes: []u8) void {
    const payload = image_bytes[0 .. image_bytes.len - 8];
    std.mem.writeInt(u64, image_bytes[image_bytes.len - 8 ..][0..8], testCapsulePayloadFingerprint(Program, payload), .little);
}

