const CountingAllocator = struct {
    child: std.mem.Allocator,
    alloc_calls: usize = 0,
    resize_calls: usize = 0,
    remap_calls: usize = 0,
    free_calls: usize = 0,
    total_allocated_bytes: usize = 0,
    largest_allocation_request: usize = 0,
    u16_aligned_alloc_calls: usize = 0,
    u16_aligned_allocated_bytes: usize = 0,
    largest_u16_alloc_request: usize = 0,

    fn init(child: std.mem.Allocator) @This() {
        return .{ .child = child };
    }

    fn allocator(self: *@This()) std.mem.Allocator {
        return .{
            .ptr = self,
            .vtable = &.{
                .alloc = alloc,
                .resize = resize,
                .remap = remap,
                .free = free,
            },
        };
    }

    fn alloc(ctx: *anyopaque, len: usize, alignment: std.mem.Alignment, ret_addr: usize) ?[*]u8 {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        self.alloc_calls += 1;
        self.recordAllocationRequest(len, alignment);
        return self.child.rawAlloc(len, alignment, ret_addr);
    }

    fn resize(ctx: *anyopaque, memory: []u8, alignment: std.mem.Alignment, new_len: usize, ret_addr: usize) bool {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        self.resize_calls += 1;
        return self.child.rawResize(memory, alignment, new_len, ret_addr);
    }

    fn remap(ctx: *anyopaque, memory: []u8, alignment: std.mem.Alignment, new_len: usize, ret_addr: usize) ?[*]u8 {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        self.remap_calls += 1;
        self.recordAllocationRequest(new_len, alignment);
        return self.child.rawRemap(memory, alignment, new_len, ret_addr);
    }

    fn free(ctx: *anyopaque, memory: []u8, alignment: std.mem.Alignment, ret_addr: usize) void {
        const self: *@This() = @ptrCast(@alignCast(ctx));
        self.free_calls += 1;
        self.child.rawFree(memory, alignment, ret_addr);
    }

    fn allocationEvents(self: @This()) usize {
        return self.alloc_calls + self.resize_calls + self.remap_calls;
    }

    fn recordAllocationRequest(self: *@This(), len: usize, alignment: std.mem.Alignment) void {
        self.total_allocated_bytes += len;
        self.largest_allocation_request = @max(self.largest_allocation_request, len);
        if (alignment == std.mem.Alignment.of(u16)) {
            self.u16_aligned_alloc_calls += 1;
            self.u16_aligned_allocated_bytes += len;
            self.largest_u16_alloc_request = @max(self.largest_u16_alloc_request, len);
        }
    }
};

fn ResumeI32OperationHandler(comptime Program: type, comptime Site: type, comptime value: i32) type {
    return struct {
        fn handle(ctx: anytype, request: anytype, control: Program.Handler.Control) !Program.Handler.Outcome(Site) {
            ctx.operation_count += 1;
            _ = try request.payload();
            _ = try control.requestFingerprint();
            return Program.Handler.@"resume"(Site, @as(Site.Resume, value));
        }
    };
}

fn ReturnNowI32OperationHandler(comptime Program: type, comptime Site: type, comptime value: i32) type {
    return struct {
        fn handle(ctx: anytype, request: anytype, control: Program.Handler.Control) !Program.Handler.Outcome(Site) {
            ctx.operation_count += 1;
            _ = try request.payload();
            _ = try control.trace();
            return Program.Handler.returnNow(Site, @as(Site.Result, value));
        }
    };
}

fn AbortReturnI32OperationHandler(comptime Program: type, comptime Site: type, comptime expected_payload: i32, comptime value: i32) type {
    return struct {
        fn handle(ctx: anytype, request: anytype, control: Program.Handler.Control) !Program.Handler.Outcome(Site) {
            ctx.operation_count += 1;
            try std.testing.expectEqual(@as(i32, expected_payload), try request.payload());
            try std.testing.expectEqual(Program.Session.ParkedKind.operation, try control.parkedKind());
            return Program.Handler.returnNow(Site, @as(Site.Result, value));
        }
    };
}

fn ResumeAfterHandler(comptime Program: type, comptime Site: type, comptime output: Site.Output) type {
    return struct {
        fn handle(ctx: anytype, request: anytype, control: Program.Handler.Control) !Program.Handler.Outcome(Site) {
            ctx.after_count += 1;
            if (comptime Site.has_static_input_ref) {
                _ = try request.value();
            }
            try std.testing.expectEqual(Program.Session.ParkedKind.after, try control.parkedKind());
            return Program.Handler.resumeAfter(Site, @as(Site.Output, output));
        }
    };
}

fn CaptureAndSuspendHandler(comptime Program: type, comptime Site: type) type {
    return struct {
        fn handle(ctx: anytype, request: anytype, control: Program.Handler.Control) !Program.Handler.Outcome(Site) {
            ctx.operation_count += 1;
            _ = try request.payload();
            ctx.captured = try control.capture(std.testing.allocator);
            return Program.Handler.@"suspend"(Site);
        }
    };
}

fn ForwardOperationHandler(comptime Program: type, comptime Site: type) type {
    return struct {
        fn handle(ctx: anytype, request: anytype, control: Program.Handler.Control) !Program.Handler.Outcome(Site) {
            ctx.operation_count += 1;
            _ = try request.payload();
            _ = try control.trace();
            return Program.Handler.forward(Site);
        }
    };
}

fn compiledTransformPlan(comptime label: []const u8) boundary.ir.ProgramPlan {
    const root = boundary.ir.builder.function(0);
    const resume_local = boundary.ir.builder.local(root, 0);
    const instructions = [_]boundary.ir.plan.Instruction{
        boundary.ir.builder.callOp(root, resume_local, boundary.ir.builder.op(root, 0), null) catch unreachable,
        boundary.ir.builder.returnValue(root, resume_local) catch unreachable,
    };
    const functions = [_]boundary.ir.plan.Function{.{
        .symbol_name = "run",
        .value_codec = .i32,
        .result_codec = .i32,
        .parameter_count = 0,
        .first_requirement = 0,
        .requirement_count = 1,
        .first_output = 0,
        .output_count = 0,
        .first_local = 0,
        .local_count = 1,
        .first_block = 0,
        .entry_block = 0,
        .block_count = 1,
        .first_instruction = 0,
        .instruction_count = @intCast(instructions.len),
    }};
    const requirements = [_]boundary.ir.plan.Requirement{.{
        .label = "authored",
        .first_op = 0,
        .op_count = 1,
    }};
    const ops = [_]boundary.ir.plan.Op{.{
        .requirement_index = 0,
        .op_name = "dispatch",
        .mode = .transform,
        .payload_codec = .unit,
        .resume_codec = .i32,
        .has_after = true,
    }};
    const blocks = [_]boundary.ir.plan.Block{.{
        .first_instruction = 0,
        .instruction_count = @intCast(instructions.len),
        .terminator_index = 0,
    }};
    const terminators = [_]boundary.ir.plan.Terminator{.{ .kind = .return_value }};

    return boundary.ir.builder.finish(.{
        .label = label,
        .ir_hash = 1,
        .entry = root,
        .functions = &functions,
        .requirements = &requirements,
        .ops = &ops,
        .outputs = &.{},
        .locals = &.{.{ .codec = .i32 }},
        .blocks = &blocks,
        .terminators = &terminators,
        .instructions = &instructions,
    }) catch unreachable;
}

