    const Body = struct {
        pub const compiled_plan = pureArithmeticPlan("contract-scalar-plan");
    };
    const Program = boundary.program("contract-scalar", struct {}, Body);

    try std.testing.expectEqualStrings("contract-scalar", Program.contract.label);
