test "Program.residualize forwards source Body encodeArgs" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const ArgHandlers = struct {
        payload: []const u8,
    };
    const Body = struct {
        pub const compiled_plan = parameterizedSessionStringOpPlan("residualize-encode-args-source");

        pub fn encodeArgs(handlers: ArgHandlers) struct { []const u8 } {
            return .{handlers.payload};
        }
    };
    const Program = boundary.program("residualize-encode-args-source", ArgHandlers, Body);
    const Source = Program.protocol.operationSite("session", "decide", 0);
    const Policy = boundary.ir.schema.Protocol(.{
        .label = "policy",
        .ops = .{
            boundary.ir.schema.transform("check", []const u8, i32),
        },
    });
    const Check = Policy.operation("check", .{});
    const Morphism = Program.ResidualMorphism(.{
        .source = Source,
        .target = Check,
        .payload = boundary.ir.expr.identity(),
        .response = Program.ResidualResponse.resumeIdentity(),
    });
    const Residual = Program.residualize(.{
        .label = "residualize-encode-args-target",
        .morphisms = .{Morphism},
    });
    const ResidualSite = Residual.protocol.operationSite("policy", "check", 0);
    const PolicyHandler = struct {
        pub fn handle(_: anytype, request: anytype, _: Residual.Handler.Control) !Residual.Handler.Outcome(ResidualSite) {
            try std.testing.expectEqualStrings("from-encode-args", try request.payload());
            return Residual.Handler.@"resume"(ResidualSite, @as(i32, 31));
        }
    };
    const Interpreter = Residual.Interpreter(.{
        Residual.Handler.operation(ResidualSite, PolicyHandler.handle),
    });

    var host = struct {}{};
    var result = try Interpreter.run(&runtime, .{ .payload = "from-encode-args" }, &host, .{});
    switch (result) {
        .done => |*done| {
            defer done.deinit();
            try std.testing.expectEqual(@as(i32, 31), done.value);
        },
        else => return error.ExpectedDone,
    }

    var session = try Residual.Session.start(&runtime, .{ .payload = "from-encode-args" });
    defer session.deinit();
    const request = switch (try session.next()) {
        .request => |value| value,
        .done => return error.ExpectedRequest,
        .after => return error.UnexpectedAfter,
    };
    try std.testing.expectEqualStrings("from-encode-args", try request.payload([]const u8));
    try session.@"resume"(request, @as(i32, 41));
    var session_done = switch (try session.next()) {
        .done => |done| done,
        .request => return error.UnexpectedRequest,
        .after => return error.UnexpectedAfter,
    };
    defer session_done.deinit();
    try std.testing.expectEqual(@as(i32, 41), session_done.value);
}

test "Program.residualize preserves source Body result cleanup" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Payload = struct {
        items: [][]const u8,
    };
    const ArgHandlers = struct {
        payload: Payload,
    };
    const CleanupState = struct {
        var result_deinit_called = false;
    };
    const Body = struct {
        pub const value_schema_types = .{Payload};
        pub const compiled_plan = sessionLastReturnThenYieldProductPlan(Payload, "residualize-result-cleanup-source");

        pub fn encodeArgs(handlers: ArgHandlers) struct { Payload } {
            return .{handlers.payload};
        }

        pub fn deinitResult(allocator: std.mem.Allocator, value: Payload) void {
            CleanupState.result_deinit_called = true;
            for (value.items) |item| allocator.free(item);
            allocator.free(value.items);
        }
    };
    const Program = boundary.program("residualize-result-cleanup-source", ArgHandlers, Body);
    const Source = Program.protocol.operationSite("last_return", "park", 0);
    const Policy = boundary.ir.schema.Protocol(.{
        .label = "policy",
        .ops = .{
            boundary.ir.schema.transform("check", void, i32),
        },
    });
    const Check = Policy.operation("check", .{});
    const Morphism = Program.ResidualMorphism(.{
        .source = Source,
        .target = Check,
        .payload = boundary.ir.expr.identity(),
        .response = Program.ResidualResponse.resumeIdentity(),
    });
    const Residual = Program.residualize(.{
        .label = "residualize-result-cleanup-target",
        .morphisms = .{Morphism},
    });

    var left = [_]u8{ 'l', 'e', 'f', 't' };
    var right = [_]u8{ 'r', 'i', 'g', 'h', 't' };
    var items = [_][]const u8{ left[0..], right[0..] };
    var session = try Residual.Session.start(&runtime, .{ .payload = .{ .items = items[0..] } });
    defer session.deinit();

    const request = switch (try session.next()) {
        .request => |parked| parked,
        .done => return error.UnexpectedDone,
        .after => return error.UnexpectedAfter,
    };
    try session.@"resume"(request, @as(i32, 7));
    var result = switch (try session.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };

    @memcpy(left[0..], "wxyz");
    @memcpy(right[0..], "omega");
    try std.testing.expectEqual(@as(usize, 2), result.value.items.len);
    try std.testing.expectEqualStrings("left", result.value.items[0]);
    try std.testing.expectEqualStrings("right", result.value.items[1]);
    try std.testing.expect(!CleanupState.result_deinit_called);
    result.deinit();
    try std.testing.expect(CleanupState.result_deinit_called);
}

test "Program.residualize rewrites choice source sites and rejects abort source sites" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Policy = boundary.ir.schema.Protocol(.{
        .label = "policy",
        .ops = .{
            boundary.ir.schema.transform("check", []const u8, i32),
        },
    });
    const Check = Policy.operation("check", .{});

    const ChoiceBody = struct {
        pub const compiled_plan = sessionStringOpPlan(.choice, "residualize-choice-source");
    };
    const ChoiceProgram = boundary.program("residualize-choice-source", struct {}, ChoiceBody);
    const ChoiceSource = ChoiceProgram.protocol.operationSite("session", "decide", 0);
    const ChoiceMorphism = ChoiceProgram.ResidualMorphism(.{
        .source = ChoiceSource,
        .target = Check,
        .payload = boundary.ir.expr.payload(),
        .response = ChoiceProgram.ResidualResponse.resumeIdentity(),
        .label = "choice-as-policy",
    });
    const ChoiceResidual = ChoiceProgram.residualize(.{
        .label = "residualize-choice-target",
        .morphisms = .{ChoiceMorphism},
    });
    try ChoiceResidual.compiled_plan.validate();
    const ChoiceResidualSite = ChoiceResidual.protocol.operationSite("policy", "check", 0);
    try std.testing.expectEqual(boundary.ir.PlanControlMode.transform, ChoiceResidualSite.op_mode);
    try std.testing.expectEqual(ChoiceSource.fingerprint, (ChoiceResidual.sourceForResidualSite(ChoiceResidualSite) orelse return error.ExpectedResidualSourceMap).source_site_fingerprint);

    const ChoiceHandler = struct {
        pub fn handle(ctx: anytype, request: anytype, _: ChoiceResidual.Handler.Control) !ChoiceResidual.Handler.Outcome(ChoiceResidualSite) {
            ctx.operation_count += 1;
            try std.testing.expectEqualStrings("payload", try request.payload());
            return ChoiceResidual.Handler.@"resume"(ChoiceResidualSite, @as(i32, 12));
        }
    };
    const ChoiceInterpreter = ChoiceResidual.Interpreter(.{
        ChoiceResidual.Handler.operation(ChoiceResidualSite, ChoiceHandler.handle),
    });
    var choice_host = struct { operation_count: usize = 0 }{};
    var choice_result = try ChoiceInterpreter.run(&runtime, .{}, &choice_host, .{});
    switch (choice_result) {
        .done => |*done_value| {
            defer done_value.deinit();
            try std.testing.expectEqual(@as(i32, 12), done_value.value);
        },
        else => return error.ExpectedDone,
    }
    try std.testing.expectEqual(@as(usize, 1), choice_host.operation_count);

    const AbortBody = struct {
        pub const compiled_plan = sessionStringOpPlan(.abort, "residualize-abort-source");
    };
    const AbortProgram = boundary.program("residualize-abort-source", struct {}, AbortBody);
    const AbortSource = AbortProgram.protocol.operationSite("session", "decide", 0);
    const AbortMorphism = AbortProgram.ResidualMorphism(.{
        .source = AbortSource,
        .target = Check,
        .payload = boundary.ir.expr.identity(),
        .response = AbortProgram.ResidualResponse.resumeIdentity(),
        .label = "abort-as-policy",
    });
    const AbortReport = AbortProgram.residualizationReport(.{ .morphisms = .{AbortMorphism} });
    try std.testing.expect(!AbortReport.supported);
    try std.testing.expectEqual(@as(usize, 1), AbortReport.unsupported.len);
    try std.testing.expectEqual(AbortProgram.ResidualBlockerTag.unsupported_source_mode, AbortReport.unsupported[0].tag);
}

