test "Program.Session capsule captures current request and restores reusable branches" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.choice, "session-capsule-request-branching");
    };
    const Program = boundary.program("session-capsule-request-branching", struct {}, Body);
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();

    switch (try session.current()) {
        .none => {},
        .request => return error.UnexpectedRequest,
        .after => return error.UnexpectedAfter,
    }

    const request = switch (try session.next()) {
        .request => |request| request,
        .done => return error.UnexpectedDone,
        .after => return error.UnexpectedAfter,
    };
    const current_request = switch (try session.current()) {
        .request => |current| current,
        .after => return error.UnexpectedAfter,
        .none => return error.UnexpectedDone,
    };
    try std.testing.expectEqual(request.fingerprint(), current_request.fingerprint());
    try std.testing.expectEqualStrings("payload", try current_request.payload([]const u8));

    var capsule = try session.capture(std.testing.allocator);
    defer capsule.deinit();
    const metadata = capsule.metadata();
    try std.testing.expectEqual(Program.Session.capsule_version, metadata.version);
    try std.testing.expectEqual(Program.Session.continuation_fingerprint_version, metadata.continuation_fingerprint_version);
    try std.testing.expectEqual(Program.Session.ParkedKind.operation, metadata.parked_kind);
    try std.testing.expectEqual(request.fingerprint(), metadata.current_request_fingerprint);
    try std.testing.expectEqual(@as(?usize, request.operation_site_index), metadata.current_operation_site_index);
    try std.testing.expectEqual(@as(?usize, null), metadata.current_after_site_index);
    try std.testing.expect(metadata.owns_copied_values);
    try std.testing.expect(metadata.reusable);
    try std.testing.expectEqual(capsule.fingerprint(), metadata.continuation_fingerprint);

    try session.returnNow(request, @as(i32, 7));
    var original_result = switch (try session.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };
    defer original_result.deinit();
    try std.testing.expectEqual(@as(i32, 7), original_result.value);

    var resumed_branch = try Program.Session.restore(&runtime, .{}, &capsule);
    defer resumed_branch.deinit();
    try std.testing.expectError(error.ProgramContractViolation, resumed_branch.@"resume"(request, @as(i32, 9)));
    const resumed_request = switch (try resumed_branch.current()) {
        .request => |current| current,
        .after => return error.UnexpectedAfter,
        .none => return error.UnexpectedDone,
    };
    try std.testing.expectEqual(request.fingerprint(), resumed_request.fingerprint());
    var recaptured = try resumed_branch.capture(std.testing.allocator);
    defer recaptured.deinit();
    try std.testing.expectEqual(capsule.fingerprint(), recaptured.fingerprint());
    try resumed_branch.@"resume"(resumed_request, @as(i32, 42));
    var resumed_result = switch (try resumed_branch.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };
    defer resumed_result.deinit();
    try std.testing.expectEqual(@as(i32, 42), resumed_result.value);

    var return_branch = try Program.Session.restore(&runtime, .{}, &capsule);
    defer return_branch.deinit();
    const return_request = switch (try return_branch.current()) {
        .request => |current| current,
        .after => return error.UnexpectedAfter,
        .none => return error.UnexpectedDone,
    };
    try std.testing.expectEqual(request.fingerprint(), return_request.fingerprint());
    try return_branch.returnNow(return_request, @as(i32, 99));
    var return_result = switch (try return_branch.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };
    defer return_result.deinit();
    try std.testing.expectEqual(@as(i32, 99), return_result.value);
}

test "Program.Session capsule image round trips deterministic bytes and restores fresh tokens" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.choice, "session-capsule-image-roundtrip");
    };
    const Program = boundary.program("session-capsule-image-roundtrip", struct {}, Body);
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();

    const request = switch (try session.next()) {
        .request => |request| request,
        .done => return error.UnexpectedDone,
        .after => return error.UnexpectedAfter,
    };
    var capsule = try session.capture(std.testing.allocator);
    defer capsule.deinit();

    var first_image = try capsule.encode(std.testing.allocator);
    defer first_image.deinit();
    var second_image = try Program.Session.Capsule.Image.fromCapsule(std.testing.allocator, &capsule);
    defer second_image.deinit();
    try std.testing.expectEqual(Program.capsule_image_format_version, first_image.image_version);
    try std.testing.expectEqual(Program.Session.capsule_image_format_version, first_image.image_version);
    try std.testing.expectEqual(capsule.fingerprint(), first_image.capsule_fingerprint);
    try std.testing.expectEqual(request.fingerprint(), first_image.current_request_fingerprint);
    try std.testing.expectEqual(first_image.image_fingerprint, second_image.image_fingerprint);
    try std.testing.expectEqualSlices(u8, first_image.bytes, second_image.bytes);

    var other_runtime = boundary.Runtime.init(std.testing.allocator);
    defer other_runtime.deinit();
    var other_session = try Program.Session.start(&other_runtime, .{});
    defer other_session.deinit();
    const other_request = switch (try other_session.next()) {
        .request => |current| current,
        .done => return error.UnexpectedDone,
        .after => return error.UnexpectedAfter,
    };
    var other_capsule = try other_session.capture(std.testing.allocator);
    defer other_capsule.deinit();
    var other_image = try other_capsule.encode(std.testing.allocator);
    defer other_image.deinit();
    try std.testing.expectEqual(request.fingerprint(), other_request.fingerprint());
    try std.testing.expectEqual(first_image.image_fingerprint, other_image.image_fingerprint);
    try std.testing.expectEqualSlices(u8, first_image.bytes, other_image.bytes);

    var decoded = try Program.Session.Capsule.decode(std.testing.allocator, first_image.bytes);
    defer decoded.deinit();
    var restored = try Program.Session.restore(&runtime, .{}, &decoded);
    defer restored.deinit();
    try std.testing.expectError(error.ProgramContractViolation, restored.@"resume"(request, @as(i32, 9)));
    const restored_request = switch (try restored.current()) {
        .request => |current| current,
        .after => return error.UnexpectedAfter,
        .none => return error.UnexpectedDone,
    };
    try std.testing.expectEqual(request.fingerprint(), restored_request.fingerprint());
    try restored.@"resume"(restored_request, @as(i32, 51));
    var restored_result = switch (try restored.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };
    defer restored_result.deinit();
    try std.testing.expectEqual(@as(i32, 51), restored_result.value);

    var corrupted = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(corrupted);
    corrupted[corrupted.len - 9] ^= 0x01;
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, corrupted));

    var excessive_steps = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(excessive_steps);
    const remaining_steps_offset = try capsuleCoreRemainingStepsOffset(excessive_steps);
    std.mem.writeInt(u64, excessive_steps[remaining_steps_offset..][0..8], interpreter_step_budget + 1, .little);
    rewriteCapsuleImageChecksum(Program, excessive_steps);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, excessive_steps));

    var done_consumed = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(done_consumed);
    done_consumed[try capsuleCoreDoneConsumedOffset(done_consumed)] = 1;
    rewriteCapsuleImageChecksum(Program, done_consumed);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, done_consumed));

    const forged_request_fingerprint = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(forged_request_fingerprint);
    try corruptLastU64Occurrence(forged_request_fingerprint, request.fingerprint());
    rewriteCapsuleImageChecksum(Program, forged_request_fingerprint);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, forged_request_fingerprint));

    var bad_dst = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(bad_dst);
    const dst_offset = try pendingOpDstOffset(bad_dst);
    std.mem.writeInt(u16, bad_dst[dst_offset..][0..2], std.math.maxInt(u16) - 1, .little);
    rewriteCapsuleImageChecksum(Program, bad_dst);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, bad_dst));

    var malformed_frame = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(malformed_frame);
    const after_start_offset = try firstCapsuleFrameAfterStartOffset(malformed_frame);
    std.mem.writeInt(u64, malformed_frame[after_start_offset..][0..8], std.math.maxInt(u64), .little);
    rewriteCapsuleImageChecksum(Program, malformed_frame);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, malformed_frame));

    var wrong_program_counter = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(wrong_program_counter);
    const frame_instruction_offset = (try firstCapsuleFrameAfterStartOffset(wrong_program_counter)) - 24;
    std.mem.writeInt(u64, wrong_program_counter[frame_instruction_offset..][0..8], 1, .little);
    rewriteCapsuleImageChecksum(Program, wrong_program_counter);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, wrong_program_counter));

    var impossible_frame_depth = try std.testing.allocator.dupe(u8, first_image.bytes);
    defer std.testing.allocator.free(impossible_frame_depth);
    const frame_count_offset = try capsuleCoreFrameCountOffset(impossible_frame_depth);
    std.mem.writeInt(u64, impossible_frame_depth[frame_count_offset..][0..8], 2, .little);
    rewriteCapsuleImageChecksum(Program, impossible_frame_depth);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Capsule.decode(std.testing.allocator, impossible_frame_depth));

    const OtherProgram = boundary.program("session-capsule-image-foreign", struct {}, Body);
    try std.testing.expectError(error.ProgramContractViolation, OtherProgram.Session.Capsule.decode(std.testing.allocator, first_image.bytes));
}

