        pub const compiled_plan = sessionLastReturnThenYieldProductPlan(Payload, "session-output-failure-result-cleanup-owned");

        pub fn encodeArgs(handlers: LastReturnHandlers) struct { Payload } {
            return .{handlers.payload};
        }

