test "Program.Exchange mailbox preserves branch id while polling parked after request" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = compiledTransformPlan("exchange-mailbox-after-branch-repoll");
    };
    const Program = boundary.program("exchange-mailbox-after-branch-repoll", struct {}, Body);
    const Outbox = struct {
        allocator: std.mem.Allocator,
        items: std.ArrayList(Program.Exchange.RequestEnvelope) = .empty,
        routes: std.ArrayList(Program.Exchange.Route) = .empty,

        fn deinit(self: *@This()) void {
            for (self.items.items) |*item| item.deinit();
            self.items.deinit(self.allocator);
            self.routes.deinit(self.allocator);
        }

        pub fn appendRouted(self: *@This(), envelope: Program.Exchange.RequestEnvelope, route: Program.Exchange.Route) !void {
            try self.items.ensureUnusedCapacity(self.allocator, 1);
            try self.routes.ensureUnusedCapacity(self.allocator, 1);
            self.items.appendAssumeCapacity(envelope);
            self.routes.appendAssumeCapacity(route);
        }

        pub fn append(self: *@This(), envelope: Program.Exchange.RequestEnvelope) !void {
            try self.items.append(self.allocator, envelope);
        }
    };
    const Inbox = struct {
        response: ?Program.Exchange.ResponseEnvelope = null,

        fn deinit(self: *@This()) void {
            if (self.response) |*response| response.deinit();
            self.response = null;
        }

        pub fn nextResponse(self: *@This()) !?Program.Exchange.ResponseEnvelope {
            const response = self.response orelse return null;
            self.response = null;
            return response;
        }
    };

    var manifest = try Program.Exchange.Manifest.encode(std.testing.allocator);
    defer manifest.deinit();
    var provider = try Program.Exchange.ProviderManifest.encode(std.testing.allocator, .{
        .label = "after-branch-provider",
        .supported_program_manifest_fingerprints = &[_]u64{manifest.fingerprint},
    });
    defer provider.deinit();
    const branch_id = "after-policy-branch";
    var capability = try Program.Exchange.Capability.encode(std.testing.allocator, .{
        .issuer_label = "host",
        .provider_fingerprint = provider.provider_fingerprint,
        .manifest_fingerprint = manifest.fingerprint,
        .journal_policy_fingerprint = Program.Exchange.journalPolicyFingerprint(branch_id),
    });
    defer capability.deinit();
    const providers = [_]Program.Exchange.ProviderManifest{provider};
    const capabilities = [_]Program.Exchange.Capability{capability};
    const router = Program.Exchange.Router{ .providers = providers[0..], .capabilities = capabilities[0..] };

    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();
    var outbox = Outbox{ .allocator = std.testing.allocator };
    defer outbox.deinit();
    var inbox = Inbox{};
    defer inbox.deinit();
    var runner = Program.Exchange.MailboxRunner{};
    defer runner.deinit();

    var operation_step = try runner.runStep(&session, &outbox, &inbox, .{ .allocator = std.testing.allocator });
    switch (operation_step) {
        .parked => |*envelope| envelope.deinit(),
        else => return error.ExpectedRequest,
    }
    try std.testing.expectEqual(@as(usize, 1), outbox.items.items.len);

    inbox.response = try Program.Exchange.ResponseEnvelope.@"resume"(std.testing.allocator, outbox.items.items[0], @as(i32, 7));
    const response_step = try runner.runStep(&session, &outbox, &inbox, .{ .allocator = std.testing.allocator });
    switch (response_step) {
        .running => {},
        else => return error.ExpectedRunning,
    }

    var after_step = try runner.runStep(&session, &outbox, &inbox, .{
        .allocator = std.testing.allocator,
        .router = router,
        .journal_branch_id = branch_id,
        .policy = .{ .require_route = true },
    });
    const after_fingerprint = switch (after_step) {
        .parked => |*envelope| blk: {
            defer envelope.deinit();
            break :blk envelope.fingerprint;
        },
        else => return error.ExpectedAfter,
    };
    try std.testing.expectEqual(@as(usize, 2), outbox.items.items.len);
    try std.testing.expectEqual(@as(usize, 1), outbox.routes.items.len);

    var after_repeat = try runner.runStep(&session, &outbox, &inbox, .{
        .allocator = std.testing.allocator,
        .router = router,
        .policy = .{ .require_route = true },
    });
    const after_repeat_fingerprint = switch (after_repeat) {
        .parked => |*envelope| blk: {
            defer envelope.deinit();
            break :blk envelope.fingerprint;
        },
        else => return error.ExpectedAfter,
    };
    try std.testing.expectEqual(after_fingerprint, after_repeat_fingerprint);
    try std.testing.expectEqual(@as(usize, 2), outbox.items.items.len);
    try std.testing.expectEqual(@as(usize, 1), outbox.routes.items.len);
}

test "Program.Exchange journal events encode decode and replay skips exchange metadata" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.transform, "journal-capability-events");
    };
    const Program = boundary.program("journal-capability-events", struct {}, Body);
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();
    var journal = Program.Session.Journal.init(std.testing.allocator);
    defer journal.deinit();
    const request = switch (try session.next()) {
        .request => |value| value,
        .after => return error.UnexpectedAfter,
        .done => return error.UnexpectedDone,
    };
    var envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{ .journal = &journal });
    defer envelope.deinit();
    try journal.appendExchangeEvent(.{
        .kind = .route_selected,
        .provider_fingerprint = 1,
        .capability_fingerprint = 2,
        .route_fingerprint = 3,
        .request_envelope_fingerprint = envelope.fingerprint,
    });
    try journal.appendExchangeEvent(.{
        .kind = .obligation_consumed,
        .capability_instance_fingerprint = 4,
        .obligation_fingerprint = 5,
        .obligation_transition_fingerprint = 6,
        .branch_id = 7,
        .request_envelope_fingerprint = envelope.fingerprint,
    });
    var response = try Program.Exchange.ResponseEnvelope.@"resume"(std.testing.allocator, envelope, @as(i32, 42));
    defer response.deinit();
    try Program.Exchange.applyResponse(&session, response, .{ .journal = &journal });
    const journal_bytes = try journal.encode(std.testing.allocator);
    defer std.testing.allocator.free(journal_bytes);
    var decoded = try Program.Session.Journal.decode(std.testing.allocator, journal_bytes);
    defer decoded.deinit();
    try std.testing.expectEqual(@as(usize, 4), decoded.entries.items.len);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.route_selected, decoded.entries.items[1].exchange_event.kind);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.obligation_consumed, decoded.entries.items[2].exchange_event.kind);
    try std.testing.expectEqual(@as(u64, 7), decoded.entries.items[2].exchange_event.branch_id.?);

    var forged_v1_exchange = try std.testing.allocator.dupe(u8, journal_bytes);
    defer std.testing.allocator.free(forged_v1_exchange);
    std.mem.writeInt(u32, forged_v1_exchange["ABL_JRN1".len..][0..4], 1, .little);
    const forged_payload = forged_v1_exchange[0 .. forged_v1_exchange.len - 8];
    std.mem.writeInt(u64, forged_v1_exchange[forged_v1_exchange.len - 8 ..][0..8], testProgramJournalFingerprint(Program, forged_payload), .little);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Journal.decode(std.testing.allocator, forged_v1_exchange));
    var forged_v2_exchange = try std.testing.allocator.dupe(u8, journal_bytes);
    defer std.testing.allocator.free(forged_v2_exchange);
    std.mem.writeInt(u32, forged_v2_exchange["ABL_JRN1".len..][0..4], 2, .little);
    const forged_v2_payload = forged_v2_exchange[0 .. forged_v2_exchange.len - 8];
    std.mem.writeInt(u64, forged_v2_exchange[forged_v2_exchange.len - 8 ..][0..8], testProgramJournalFingerprint(Program, forged_v2_payload), .little);
    try std.testing.expectError(error.ProgramContractViolation, Program.Session.Journal.decode(std.testing.allocator, forged_v2_exchange));

    var replay_session = try Program.Session.start(&runtime, .{});
    defer replay_session.deinit();
    _ = try replay_session.next();
    var replayer = decoded.replayer();
    defer replayer.deinit();
    const replayed = try replayer.expectCurrentValue(try replay_session.current(), i32);
    try std.testing.expectEqual(@as(i32, 42), replayed);
}

test "Program.Exchange treaty journal events encode and decode sidecar fields" {
    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.transform, "journal-treaty-events");
    };
    const Program = boundary.program("journal-treaty-events", struct {}, Body);
    var journal = Program.Session.Journal.init(std.testing.allocator);
    defer journal.deinit();
    try journal.appendExchangeEvent(.{
        .kind = .provider_offer_recorded,
        .provider_fingerprint = 11,
        .provider_offer_fingerprint = 12,
    });
    try journal.appendExchangeEvent(.{
        .kind = .morphism_offer_recorded,
        .morphism_offer_fingerprint = 13,
    });
    try journal.appendExchangeEvent(.{
        .kind = .treaty_selected,
        .provider_fingerprint = 14,
        .capability_fingerprint = 15,
        .route_fingerprint = 16,
        .request_envelope_fingerprint = 17,
        .treaty_fingerprint = 18,
        .treaty_certificate_fingerprint = 19,
        .provider_offer_fingerprint = 20,
    });
    try journal.appendExchangeEvent(.{
        .kind = .treaty_authorization_recorded,
        .authorization_fingerprint = 21,
        .response_envelope_fingerprint = 22,
        .treaty_fingerprint = 18,
        .treaty_certificate_fingerprint = 19,
        .provider_offer_fingerprint = 20,
    });
    try journal.appendExchangeEvent(.{
        .kind = .treaty_response_accepted,
        .response_envelope_fingerprint = 23,
        .treaty_fingerprint = 18,
        .treaty_certificate_fingerprint = 19,
        .provider_offer_fingerprint = 20,
    });
    try journal.appendExchangeEvent(.{
        .kind = .treaty_response_rejected,
        .response_envelope_fingerprint = 24,
        .treaty_fingerprint = 18,
        .treaty_certificate_fingerprint = 19,
        .provider_offer_fingerprint = 20,
        .blocker_tag = @tagName(Program.Exchange.Treaty.BlockerTag.wrong_route),
    });
    const bytes = try journal.encode(std.testing.allocator);
    defer std.testing.allocator.free(bytes);
    var decoded = try Program.Session.Journal.decode(std.testing.allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqual(@as(usize, 6), decoded.entries.items.len);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.provider_offer_recorded, decoded.entries.items[0].exchange_event.kind);
    try std.testing.expectEqual(@as(u64, 12), decoded.entries.items[0].exchange_event.provider_offer_fingerprint.?);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.morphism_offer_recorded, decoded.entries.items[1].exchange_event.kind);
    try std.testing.expectEqual(@as(u64, 13), decoded.entries.items[1].exchange_event.morphism_offer_fingerprint.?);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.treaty_selected, decoded.entries.items[2].exchange_event.kind);
    try std.testing.expectEqual(@as(u64, 18), decoded.entries.items[2].exchange_event.treaty_fingerprint.?);
    try std.testing.expectEqual(@as(u64, 19), decoded.entries.items[3].exchange_event.treaty_certificate_fingerprint.?);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.treaty_response_accepted, decoded.entries.items[4].exchange_event.kind);
    try std.testing.expectEqual(Program.Session.Journal.ExchangeEvent.Kind.treaty_response_rejected, decoded.entries.items[5].exchange_event.kind);
    try std.testing.expectEqualStrings(@tagName(Program.Exchange.Treaty.BlockerTag.wrong_route), decoded.entries.items[5].exchange_event.blocker_tag.?);
}

test "Program.Exchange provider offer fingerprints supports request and enforces byte limits" {
    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.transform, "provider-offer-support");
    };
    const Program = boundary.program("provider-offer-support", struct {}, Body);

    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();
    const request = switch (try session.next()) {
        .request => |value| value,
        .after => return error.UnexpectedAfter,
        .done => return error.UnexpectedDone,
    };
    const trace = request.trace();
    var manifest = try Program.Exchange.Manifest.encode(std.testing.allocator);
    defer manifest.deinit();
    var envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{});
    defer envelope.deinit();
    const response_refs = [_]@TypeOf(trace.resume_ref){trace.resume_ref};

    var offer = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "approval-direct-offer",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
        .supported_operation_sites = &.{trace.operation_site_index},
        .supported_protocol_op_fingerprints = &.{trace.operation_site_fingerprint},
        .supported_protocol_labels = &.{trace.requirement_label},
        .produced_response_refs = response_refs[0..],
        .max_request_bytes = envelope.bytes.len,
    });
    defer offer.deinit();
    var decoded = try Program.Exchange.ProviderOffer.decode(std.testing.allocator, offer.bytes);
    defer decoded.deinit();
    try std.testing.expectEqual(offer.fingerprint, decoded.fingerprint);
    try std.testing.expect(decoded.supportsRequest(envelope));

    var zero_response_limit = try std.testing.allocator.dupe(u8, offer.bytes);
    defer std.testing.allocator.free(zero_response_limit);
    var zero_response_cursor = TestImageCursor{ .bytes = zero_response_limit[0 .. zero_response_limit.len - 8] };
    try zero_response_cursor.skip("ABL_EXO1".len + 4 + 4);
    try zero_response_cursor.skipLenBytes();
    try zero_response_cursor.skip(8 + 8);
    try zero_response_cursor.skipUsizeList();
    try zero_response_cursor.skipUsizeList();
    try zero_response_cursor.skipU64List();
    try zero_response_cursor.skipStringList();
    try zero_response_cursor.skipValueRefList();
    try zero_response_cursor.skipValueRefList();
    try zero_response_cursor.skipValueRefList();
    try zero_response_cursor.skip(3 + 5 + 4 + 4 + 6 + 1 + 1);
    const provider_offer_max_response_offset = zero_response_cursor.index + 8;
    std.mem.writeInt(u64, zero_response_limit[provider_offer_max_response_offset..][0..8], 0, .little);
    const zero_response_payload = zero_response_limit[0 .. zero_response_limit.len - 8];
    std.mem.writeInt(u64, zero_response_limit[zero_response_limit.len - 8 ..][0..8], testExchangeFingerprint("boundary.exchange.provider_offer", Program.Exchange.provider_offer_fingerprint_version, zero_response_payload), .little);
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.ProviderOffer.decode(std.testing.allocator, zero_response_limit));

    var too_small = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "too-small-offer",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
        .supported_operation_sites = &.{trace.operation_site_index},
        .supported_protocol_op_fingerprints = &.{trace.operation_site_fingerprint},
        .supported_protocol_labels = &.{trace.requirement_label},
        .produced_response_refs = response_refs[0..],
        .max_request_bytes = envelope.bytes.len - 1,
    });
    defer too_small.deinit();
    try std.testing.expect(!too_small.supportsRequest(envelope));
    const wrong_payload_refs = [_]boundary.ir.ValueRef{.{ .codec = .unit }};
    var wrong_payload = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "wrong-payload-offer",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
        .supported_operation_sites = &.{trace.operation_site_index},
        .supported_protocol_op_fingerprints = &.{trace.operation_site_fingerprint},
        .supported_protocol_labels = &.{trace.requirement_label},
        .accepted_payload_refs = wrong_payload_refs[0..],
        .produced_response_refs = response_refs[0..],
        .max_request_bytes = envelope.bytes.len,
    });
    defer wrong_payload.deinit();
    try std.testing.expect(!wrong_payload.supportsRequest(envelope));
    var no_fresh_default = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "no-fresh-default-offer",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
        .supported_operation_sites = &.{trace.operation_site_index},
        .supported_protocol_op_fingerprints = &.{trace.operation_site_fingerprint},
        .supported_protocol_labels = &.{trace.requirement_label},
        .produced_response_refs = response_refs[0..],
        .max_request_bytes = envelope.bytes.len,
        .supported_replay_policies = .{ .fresh = false },
    });
    defer no_fresh_default.deinit();
    try std.testing.expect(!no_fresh_default.supportsRequest(envelope));
    var no_fresh_response_default = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "no-fresh-response-default-offer",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
        .supported_operation_sites = &.{trace.operation_site_index},
        .supported_protocol_op_fingerprints = &.{trace.operation_site_fingerprint},
        .supported_protocol_labels = &.{trace.requirement_label},
        .produced_response_refs = response_refs[0..],
        .max_request_bytes = envelope.bytes.len,
        .supported_response_uses = .{ .fresh = false },
    });
    defer no_fresh_response_default.deinit();
    try std.testing.expect(!no_fresh_response_default.supportsRequest(envelope));
    var no_unrestricted_default = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "no-unrestricted-default-offer",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
        .supported_operation_sites = &.{trace.operation_site_index},
        .supported_protocol_op_fingerprints = &.{trace.operation_site_fingerprint},
        .supported_protocol_labels = &.{trace.requirement_label},
        .produced_response_refs = response_refs[0..],
        .max_request_bytes = envelope.bytes.len,
        .supported_branch_policies = .{ .unrestricted = false },
    });
    defer no_unrestricted_default.deinit();
    try std.testing.expect(!no_unrestricted_default.supportsRequest(envelope));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "",
        .provider_fingerprint = 0xabc,
        .manifest_fingerprint = manifest.fingerprint,
    }));
}

test "Program.Exchange ProviderHarness derives provider catalog and rejects foreign manual offers" {
    const Body = struct {
        pub const compiled_plan = compiledTransformPlan("provider-harness-catalog");
    };
    const Program = boundary.program("provider-harness-catalog", struct {}, Body);
    const OperationSite = Program.protocol.operationSite("authored", "dispatch", 0);
    const AfterSite = Program.protocol.afterSite("authored", "dispatch", 0);
    const Harness = Program.Exchange.ProviderHarness(.{
        .label = "harness-provider",
        .provider_fingerprint = @as(?u64, 0x5150),
        .entries = .{
            Program.Exchange.ProviderHandler.operation(OperationSite, struct {}, .{ .label = "dispatch-request" }),
            Program.Exchange.ProviderHandler.after(AfterSite, struct {}, .{ .label = "dispatch-after" }),
        },
        .semantic_tags = &.{"derived"},
        .metadata = "harness-meta",
    });
    comptime Harness.assertCoversAll();

    try std.testing.expectEqual(@as(usize, 2), Harness.offer_count);
    try std.testing.expectEqual(@as(usize, 1), Harness.handled_operation_site_count);
    try std.testing.expectEqual(@as(usize, 1), Harness.handled_after_site_count);
    try std.testing.expectEqual(@as(u64, 0x5150), Harness.metadata.provider_fingerprint);

    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();
    const request = switch (try session.next()) {
        .request => |value| value,
        .after => return error.UnexpectedAfter,
        .done => return error.UnexpectedDone,
    };
    var request_envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{});
    defer request_envelope.deinit();

    var catalog = try Harness.buildCatalog(std.testing.allocator);
    defer catalog.deinit();
    try std.testing.expectEqual(catalog.manifest.fingerprint, Program.Exchange.exchange_manifest_fingerprint_value);
    try std.testing.expectEqual(catalog.manifest.fingerprint, catalog.provider_manifest.supported_program_manifest_fingerprints[0]);
    try std.testing.expectEqual(Harness.provider_fingerprint, catalog.provider_manifest.provider_fingerprint);
    try std.testing.expectEqualStrings("harness-provider", catalog.provider_manifest.label);
    try std.testing.expectEqualStrings("harness-meta", catalog.provider_manifest.metadata);
    try std.testing.expectEqual(@as(usize, 2), catalog.provider_offers.len);
    try std.testing.expectEqual(catalog.provider_offers[0].fingerprint, catalog.offer_fingerprints[0]);
    try std.testing.expectEqual(catalog.provider_offers[1].fingerprint, catalog.offer_fingerprints[1]);
    try std.testing.expect(catalog.provider_manifest.supportsRequest(request_envelope));
    try std.testing.expect(catalog.provider_offers[0].supportsRequest(request_envelope));
    try std.testing.expectEqual(Program.exchange_provider_offer_format_version, catalog.provider_offers[0].format_version);
    try std.testing.expectEqual(@as(?u64, null), catalog.provider_offers[0].provider_program_mapping_fingerprint);
    try std.testing.expectEqual(Program.Evidence.SemanticBody.host_intrinsic, Harness.declarationSemanticBody(0));
    try std.testing.expectEqual(Program.Evidence.SemanticBody.host_intrinsic, catalog.provider_offers[0].semanticBody());
    try std.testing.expect(catalog.provider_offers[0].hostIntrinsicRef() != null);
    try std.testing.expect(catalog.provider_offers[0].programBodyRef() == null);
    const function_report = Harness.defunctionalizationReport();
    try std.testing.expectEqual(@as(usize, 2), function_report.total_bodies);
    try std.testing.expectEqual(@as(usize, 2), function_report.host_intrinsic_count);
    try std.testing.expectEqual(@as(usize, 0), function_report.boundary_program_count);
    try std.testing.expectEqual(@as(usize, 2), function_report.intrinsic_refs.len);
    try std.testing.expectError(error.HostIntrinsicsPresent, function_report.assertNoHostIntrinsics());
    try std.testing.expectError(error.HostIntrinsicsPresent, Harness.assertDefunctionalized(Program.Evidence.DefunctionalizationPolicy.strict()));
    const first_intrinsic = Harness.declarationHostIntrinsic(0) orelse return error.ExpectedHostIntrinsic;
    const first_offer_intrinsic = catalog.provider_offers[0].hostIntrinsic() orelse return error.ExpectedHostIntrinsic;
    try std.testing.expectEqual(first_intrinsic.fingerprint, first_offer_intrinsic.fingerprint);
    try std.testing.expect(first_intrinsic.provider_offer_policy_fingerprint != null);
    try std.testing.expectEqual(first_intrinsic.provider_offer_policy_fingerprint, first_offer_intrinsic.provider_offer_policy_fingerprint);
    try std.testing.expectEqual(first_intrinsic.fingerprint, function_report.intrinsic_refs[0].fingerprint);
    var authority_changed_offer = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "dispatch-request",
        .provider_fingerprint = Harness.provider_fingerprint,
        .manifest_fingerprint = catalog.manifest.fingerprint,
        .supported_operation_sites = &.{OperationSite.index},
        .supported_protocol_op_fingerprints = &.{OperationSite.fingerprint},
        .supported_protocol_labels = &.{OperationSite.requirement_label},
        .accepted_payload_refs = catalog.provider_offers[0].accepted_payload_refs,
        .produced_response_refs = catalog.provider_offers[0].produced_response_refs,
        .supported_response_uses = .{ .fresh = false },
    });
    defer authority_changed_offer.deinit();
    const authority_changed_intrinsic = authority_changed_offer.hostIntrinsic() orelse return error.ExpectedHostIntrinsic;
    try std.testing.expect(authority_changed_intrinsic.fingerprint != first_intrinsic.fingerprint);
    var operation_and_after_offer = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "dispatch-request",
        .provider_fingerprint = Harness.provider_fingerprint,
        .manifest_fingerprint = catalog.manifest.fingerprint,
        .supported_operation_sites = &.{OperationSite.index},
        .supported_after_sites = &.{AfterSite.index},
        .supported_protocol_op_fingerprints = &.{OperationSite.fingerprint},
        .supported_protocol_labels = &.{OperationSite.requirement_label},
        .accepted_payload_refs = catalog.provider_offers[0].accepted_payload_refs,
        .accepted_current_value_refs = catalog.provider_offers[1].accepted_current_value_refs,
        .produced_response_refs = catalog.provider_offers[0].produced_response_refs,
        .supported_response_uses = .{ .fresh = false },
    });
    defer operation_and_after_offer.deinit();
    var operation_without_after_offer = try Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "dispatch-request",
        .provider_fingerprint = Harness.provider_fingerprint,
        .manifest_fingerprint = catalog.manifest.fingerprint,
        .supported_operation_sites = &.{OperationSite.index},
        .supported_protocol_op_fingerprints = &.{OperationSite.fingerprint},
        .supported_protocol_labels = &.{OperationSite.requirement_label},
        .accepted_payload_refs = catalog.provider_offers[0].accepted_payload_refs,
        .produced_response_refs = catalog.provider_offers[0].produced_response_refs,
        .supported_response_uses = .{ .fresh = false },
    });
    defer operation_without_after_offer.deinit();
    const operation_and_after_intrinsic = operation_and_after_offer.hostIntrinsic() orelse return error.ExpectedHostIntrinsic;
    const operation_without_after_intrinsic = operation_without_after_offer.hostIntrinsic() orelse return error.ExpectedHostIntrinsic;
    try std.testing.expect(operation_and_after_intrinsic.fingerprint != operation_without_after_intrinsic.fingerprint);
    try std.testing.expectEqual(@as(usize, 1), operation_and_after_intrinsic.allowed_site_indexes.len);
    try std.testing.expectEqual(@as(usize, 1), operation_and_after_intrinsic.allowed_after_site_indexes.len);
    try function_report.assertOnlyAllowlistedIntrinsics(.{
        .label = "world_boundary",
        .allow_host_intrinsics = true,
        .reject_unknown = true,
        .allowed_intrinsic_fingerprints = &.{ first_intrinsic.fingerprint, (Harness.declarationHostIntrinsic(1) orelse return error.ExpectedHostIntrinsic).fingerprint },
    });
    try std.testing.expectError(error.HostIntrinsicsPresent, function_report.assertOnlyAllowlistedIntrinsics(.{
        .label = "program-backed-provider-required",
        .allow_host_intrinsics = true,
        .reject_unknown = true,
        .allowed_intrinsic_fingerprints = &.{ first_intrinsic.fingerprint, (Harness.declarationHostIntrinsic(1) orelse return error.ExpectedHostIntrinsic).fingerprint },
        .require_program_backed_providers = true,
    }));
    var capability = try Program.Exchange.Capability.encode(std.testing.allocator, .{
        .issuer_label = "harness-issuer",
        .provider_fingerprint = Harness.provider_fingerprint,
        .manifest_fingerprint = catalog.manifest.fingerprint,
        .allowed_request_kinds = .{ .operation = true, .after = false },
        .allowed_operation_sites = &.{OperationSite.index},
        .allowed_protocol_op_fingerprints = &.{OperationSite.fingerprint},
        .allowed_requirement_labels = &.{"authored"},
        .allowed_op_names = &.{"dispatch"},
        .allowed_response_refs = catalog.provider_offers[0].produced_response_refs,
    });
    defer capability.deinit();
    const providers = [_]Program.Exchange.ProviderManifest{catalog.provider_manifest};
    const offers = [_]Program.Exchange.ProviderOffer{catalog.provider_offers[0]};
    const capabilities = [_]Program.Exchange.Capability{capability};
    var allowlisted_by_harness_report = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = catalog.manifest,
        .provider_manifests = providers[0..],
        .provider_offers = offers[0..],
        .capabilities = capabilities[0..],
        .treaty_policy = .{ .defunctionalization_policy = .{
            .label = "harness-report-allowlist",
            .allow_host_intrinsics = true,
            .reject_unknown = true,
            .allowed_intrinsic_fingerprints = &.{function_report.intrinsic_refs[0].fingerprint},
        } },
    });
    defer allowlisted_by_harness_report.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.treaty, allowlisted_by_harness_report.status);
    var mixed_policy_reject = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = catalog.manifest,
        .provider_manifests = providers[0..],
        .provider_offers = offers[0..],
        .capabilities = capabilities[0..],
        .treaty_policy = .{
            .reject_intrinsic_provider = true,
            .defunctionalization_policy = .{
                .label = "explicit-but-provider-rejected",
                .allow_host_intrinsics = true,
                .reject_unknown = true,
                .allowed_intrinsic_fingerprints = &.{function_report.intrinsic_refs[0].fingerprint},
            },
        },
    });
    defer mixed_policy_reject.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.blocked, mixed_policy_reject.status);
    var saw_mixed_policy_provider_rejected = false;
    for (mixed_policy_reject.blockers.blockers[0..mixed_policy_reject.blockers.count]) |blocker| {
        if (blocker.tag == .intrinsic_provider_rejected) saw_mixed_policy_provider_rejected = true;
    }
    try std.testing.expect(saw_mixed_policy_provider_rejected);
    var mixed_policy_response = try Program.Exchange.ResponseEnvelope.@"resume"(std.testing.allocator, request_envelope, @as(i32, 7));
    defer mixed_policy_response.deinit();
    try mixed_policy_response.authorizeTreaty(allowlisted_by_harness_report.treaty.?, .fresh);
    const mixed_policy_response_report = Program.Exchange.validateTreatyResponseWithPolicy(
        allowlisted_by_harness_report.treaty.?,
        request_envelope,
        mixed_policy_response,
        .{
            .reject_intrinsic_provider = true,
            .defunctionalization_policy = .{
                .label = "explicit-but-provider-rejected",
                .allow_host_intrinsics = true,
                .reject_unknown = true,
                .allowed_intrinsic_fingerprints = &.{function_report.intrinsic_refs[0].fingerprint},
            },
        },
    );
    try std.testing.expect(!mixed_policy_response_report.allowed());
    try std.testing.expectEqualStrings("intrinsic_provider_rejected", mixed_policy_response_report.firstTagName().?);
    try std.testing.expectError(error.HostIntrinsicsPresent, allowlisted_by_harness_report.assertDefunctionalized(.{
        .label = "program-backed-provider-required",
        .allow_host_intrinsics = true,
        .reject_unknown = true,
        .allowed_intrinsic_fingerprints = &.{function_report.intrinsic_refs[0].fingerprint},
        .require_program_backed_providers = true,
    }));
    var owned_ref_catalog = try Harness.buildCatalog(std.testing.allocator);
    var owned_ref_catalog_live = true;
    defer if (owned_ref_catalog_live) owned_ref_catalog.deinit();
    const owned_ref_providers = [_]Program.Exchange.ProviderManifest{owned_ref_catalog.provider_manifest};
    const owned_ref_offers = [_]Program.Exchange.ProviderOffer{owned_ref_catalog.provider_offers[0]};
    var owned_ref_result = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = owned_ref_catalog.manifest,
        .provider_manifests = owned_ref_providers[0..],
        .provider_offers = owned_ref_offers[0..],
        .capabilities = capabilities[0..],
        .treaty_policy = .{ .defunctionalization_policy = .{
            .label = "harness-label-allowlist",
            .allow_host_intrinsics = true,
            .reject_unknown = true,
            .allowed_intrinsic_labels = &.{"dispatch-request"},
        } },
    });
    defer owned_ref_result.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.treaty, owned_ref_result.status);
    const owned_ref_label = owned_ref_result.treaty.?.provider_intrinsic_ref.?.label orelse return error.ExpectedHostIntrinsic;
    try std.testing.expect(owned_ref_label.ptr != owned_ref_catalog.provider_offers[0].label.ptr);
    owned_ref_catalog.deinit();
    owned_ref_catalog_live = false;
    try owned_ref_result.treaty.?.checkCertificate();
    try owned_ref_result.treaty.?.assertDefunctionalized(.{
        .label = "post-catalog-release-label-allowlist",
        .allow_host_intrinsics = true,
        .reject_unknown = true,
        .allowed_intrinsic_labels = &.{"dispatch-request"},
    });
    try Harness.validateManualCatalog(std.testing.allocator, catalog.provider_manifest, catalog.provider_offers);

    const HandlerBody = struct {
        pub const compiled_plan = pureArithmeticPlan("program-backed-provider-catalog-handler");
    };
    const HandlerProgram = boundary.program("program-backed-provider-catalog-handler", struct {}, HandlerBody);
    const ProgramBackedDecl = Program.Exchange.ProviderHandler.program(.{
        .label = "program-backed-dispatch",
        .op = OperationSite,
        .program = HandlerProgram,
        .map_request = .unit_args,
        .map_result = .result_to_resume,
    });
    const ProgramBackedHarness = Program.Exchange.ProviderHarness(.{
        .label = "program-backed-harness-provider",
        .provider_fingerprint = @as(?u64, 0x5158),
        .entries = .{ProgramBackedDecl},
    });
    var program_catalog = try ProgramBackedHarness.buildCatalog(std.testing.allocator);
    defer program_catalog.deinit();
    try std.testing.expectEqual(@as(usize, 1), program_catalog.provider_offers.len);
    try std.testing.expect(program_catalog.provider_manifest.supportsRequest(request_envelope));
    try std.testing.expect(program_catalog.provider_offers[0].supportsRequest(request_envelope));
    try std.testing.expectEqual(Program.exchange_provider_program_offer_format_version, Program.Exchange.provider_program_offer_format_version);
    try std.testing.expectEqual(Program.Exchange.provider_program_offer_format_version, program_catalog.provider_offers[0].format_version);
    try std.testing.expectEqual(
        @as(?u64, ProgramBackedDecl.provider_program_mapping_fingerprint),
        program_catalog.provider_offers[0].provider_program_mapping_fingerprint,
    );
    try std.testing.expectEqual(@as(usize, 1), program_catalog.provider_manifest.supported_provider_program_mapping_fingerprints.len);
    try std.testing.expectEqual(ProgramBackedDecl.provider_program_mapping_fingerprint, program_catalog.provider_manifest.supported_provider_program_mapping_fingerprints[0]);
    const program_offer_options = ProgramBackedHarness.offerOptions(0, program_catalog.manifest.fingerprint);
    try std.testing.expectEqual(@as(?u64, ProgramBackedDecl.provider_program_mapping_fingerprint), program_offer_options.provider_program_mapping_fingerprint);
    try std.testing.expectEqual(Program.Exchange.RequestToProgramArgs.unit_args, program_offer_options.provider_program_request_mapping.?);
    try std.testing.expectEqual(Program.Exchange.ProgramResultToProviderOutcome.result_to_resume, program_offer_options.provider_program_result_mapping.?);
    try std.testing.expectEqual(Program.Evidence.SemanticBody.boundary_program, ProgramBackedHarness.declarationSemanticBody(0));
    try std.testing.expectEqual(Program.Evidence.SemanticBody.unknown, program_catalog.provider_offers[0].semanticBody());
    try std.testing.expectEqual(Program.Evidence.SemanticBody.boundary_program, program_catalog.provider_offers[0].semanticBodyWithProvider(program_catalog.provider_manifest));
    try std.testing.expect(program_catalog.provider_offers[0].hostIntrinsicRef() == null);
    try std.testing.expect(program_catalog.provider_offers[0].programBodyRef() != null);
    const program_report = ProgramBackedHarness.defunctionalizationReport();
    try std.testing.expectEqual(@as(usize, 1), program_report.total_bodies);
    try std.testing.expectEqual(@as(usize, 1), program_report.boundary_program_count);
    try std.testing.expectEqual(@as(usize, 0), program_report.host_intrinsic_count);
    try ProgramBackedHarness.assertDefunctionalized(Program.Evidence.DefunctionalizationPolicy.strict());
    try std.testing.expect(ProgramBackedDecl.provider_program_mapping_fingerprint != 0);
    const provider_program_ref = Program.Evidence.refFor(Program.Evidence.domains.program_plan, HandlerProgram.compiled_plan.hash(), .{ .label = HandlerProgram.contract.label });
    try std.testing.expect(program_catalog.provider_offers[0].provider_program_ref.?.eql(provider_program_ref));
    try std.testing.expectEqual(Program.Exchange.RequestToProgramArgs.unit_args, program_catalog.provider_offers[0].provider_program_request_mapping.?);
    try std.testing.expectEqual(Program.Exchange.ProgramResultToProviderOutcome.result_to_resume, program_catalog.provider_offers[0].provider_program_result_mapping.?);
    try std.testing.expectEqual(@as(?usize, 0), program_catalog.provider_offers[0].provider_program_effect_shape_count);
    try std.testing.expectEqual(
        @as(?u64, Program.Evidence.fingerprintBoundaryEffectShapeSet(&.{})),
        program_catalog.provider_offers[0].provider_program_effect_shape_fingerprint,
    );
    var unbound_ref_offer = program_catalog.provider_offers[0];
    unbound_ref_offer.provider_program_ref.?.format_version = 1;
    try std.testing.expectError(error.ProgramContractViolation, unbound_ref_offer.validate());
    try std.testing.expect(!unbound_ref_offer.providerProgramMappingAttested());
    try ProgramBackedHarness.validateManualOffer(std.testing.allocator, 0, program_catalog.provider_offers[0]);
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.ProviderOffer.encode(std.testing.allocator, .{
        .label = "forged-program-offer",
        .provider_fingerprint = ProgramBackedHarness.provider_fingerprint,
        .manifest_fingerprint = program_catalog.manifest.fingerprint,
        .supported_operation_sites = &.{OperationSite.index},
        .supported_protocol_op_fingerprints = &.{OperationSite.fingerprint},
        .supported_protocol_labels = &.{OperationSite.requirement_label},
        .produced_response_refs = program_catalog.provider_offers[0].produced_response_refs,
        .provider_program_mapping_fingerprint = ProgramBackedDecl.provider_program_mapping_fingerprint,
    }));

    var program_capability = try Program.Exchange.Capability.encode(std.testing.allocator, .{
        .issuer_label = "program-backed-issuer",
        .provider_fingerprint = ProgramBackedHarness.provider_fingerprint,
        .manifest_fingerprint = program_catalog.manifest.fingerprint,
        .allowed_request_kinds = .{ .operation = true, .after = false },
        .allowed_operation_sites = &.{OperationSite.index},
        .allowed_protocol_op_fingerprints = &.{OperationSite.fingerprint},
        .allowed_requirement_labels = &.{"authored"},
        .allowed_op_names = &.{"dispatch"},
        .allowed_response_refs = program_catalog.provider_offers[0].produced_response_refs,
    });
    defer program_capability.deinit();
    var tampered_program_provider = program_catalog.provider_manifest;
    tampered_program_provider.max_response_envelope_bytes -= 1;
    const tampered_program_providers = [_]Program.Exchange.ProviderManifest{tampered_program_provider};
    const tampered_program_offers = [_]Program.Exchange.ProviderOffer{program_catalog.provider_offers[0]};
    const tampered_program_capabilities = [_]Program.Exchange.Capability{program_capability};
    var tampered_program_blocked = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = program_catalog.manifest,
        .provider_manifests = tampered_program_providers[0..],
        .provider_offers = tampered_program_offers[0..],
        .capabilities = tampered_program_capabilities[0..],
        .treaty_policy = .{ .defunctionalization_policy = Program.Evidence.DefunctionalizationPolicy.strict() },
    });
    defer tampered_program_blocked.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.blocked, tampered_program_blocked.status);
    var saw_tampered_program_provider = false;
    for (tampered_program_blocked.blockers.blockers[0..tampered_program_blocked.blockers.count]) |blocker| {
        if (blocker.tag == .malformed_offer) saw_tampered_program_provider = true;
    }
    try std.testing.expect(saw_tampered_program_provider);
    var tampered_program_offer = program_catalog.provider_offers[0];
    tampered_program_offer.format_version = Program.exchange_provider_offer_format_version;
    const tampered_offer_providers = [_]Program.Exchange.ProviderManifest{program_catalog.provider_manifest};
    const tampered_offer_offers = [_]Program.Exchange.ProviderOffer{tampered_program_offer};
    var tampered_offer_blocked = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = program_catalog.manifest,
        .provider_manifests = tampered_offer_providers[0..],
        .provider_offers = tampered_offer_offers[0..],
        .capabilities = tampered_program_capabilities[0..],
        .treaty_policy = .{ .defunctionalization_policy = Program.Evidence.DefunctionalizationPolicy.strict() },
    });
    defer tampered_offer_blocked.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.blocked, tampered_offer_blocked.status);
    var saw_tampered_offer_malformed = false;
    var saw_tampered_offer_unknown = false;
    for (tampered_offer_blocked.blockers.blockers[0..tampered_offer_blocked.blockers.count]) |blocker| {
        if (blocker.tag == .malformed_offer) saw_tampered_offer_malformed = true;
        if (blocker.tag == .unknown_semantic_body) saw_tampered_offer_unknown = true;
    }
    try std.testing.expect(saw_tampered_offer_malformed);
    try std.testing.expect(!saw_tampered_offer_unknown);
    const mixed_providers = [_]Program.Exchange.ProviderManifest{ catalog.provider_manifest, program_catalog.provider_manifest };
    const mixed_offers = [_]Program.Exchange.ProviderOffer{ catalog.provider_offers[0], program_catalog.provider_offers[0] };
    const mixed_capabilities = [_]Program.Exchange.Capability{ capability, program_capability };
    var default_mixed = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = catalog.manifest,
        .provider_manifests = mixed_providers[0..],
        .provider_offers = mixed_offers[0..],
        .capabilities = mixed_capabilities[0..],
    });
    defer default_mixed.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.ambiguous_treaties, default_mixed.status);
    var preferred_mixed = try Program.Exchange.TreatyResolver.resolve(.{
        .allocator = std.testing.allocator,
        .request = request_envelope,
        .manifest = catalog.manifest,
        .provider_manifests = mixed_providers[0..],
        .provider_offers = mixed_offers[0..],
        .capabilities = mixed_capabilities[0..],
        .treaty_policy = .{ .prefer_program_backed_provider = true },
    });
    defer preferred_mixed.deinit();
    try std.testing.expectEqual(Program.Exchange.TreatyResolver.Status.treaty, preferred_mixed.status);
    try std.testing.expectEqual(ProgramBackedHarness.provider_fingerprint, preferred_mixed.treaty.?.provider_fingerprint);
    try std.testing.expectEqual(Program.Evidence.SemanticBody.boundary_program, preferred_mixed.treaty.?.provider_semantic_body);
    const static_operation_shape = Program.Evidence.BoundaryEffectShape.init(.{
        .program_label = Program.contract.label,
        .plan_label = Program.compiled_plan.label,
        .plan_hash = Program.compiled_plan.hash(),
