test "Program.Exchange capsule restore requires capability permission" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.choice, "capability-capsule-restore");
    };
    const Program = boundary.program("capability-capsule-restore", struct {}, Body);
    var manifest = try Program.Exchange.Manifest.encode(std.testing.allocator);
    defer manifest.deinit();
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();
    const request = switch (try session.next()) {
        .request => |value| value,
        .after => return error.UnexpectedAfter,
        .done => return error.UnexpectedDone,
    };
    var capsule = try session.capture(std.testing.allocator);
    defer capsule.deinit();
    var image = try capsule.encode(std.testing.allocator);
    defer image.deinit();
    var envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{ .capsule = image });
    defer envelope.deinit();
    var provider = try Program.Exchange.ProviderManifest.encode(std.testing.allocator, .{
        .label = "capsule-provider",
        .supported_program_manifest_fingerprints = &[_]u64{manifest.fingerprint},
        .supported_operation_sites = &[_]usize{envelope.site_index},
        .accepts_capsule_restore = true,
    });
    defer provider.deinit();
    var denied = try Program.Exchange.Capability.encode(std.testing.allocator, .{
        .issuer_label = "host",
        .provider_fingerprint = provider.provider_fingerprint,
        .manifest_fingerprint = manifest.fingerprint,
        .allowed_operation_sites = &[_]usize{envelope.site_index},
        .allow_capsule_restore = false,
        .max_capsule_image_bytes = envelope.capsule_image.?.len,
    });
    defer denied.deinit();
    var restore_runtime = boundary.Runtime.init(std.testing.allocator);
    defer restore_runtime.deinit();
    const denied_route = Program.Exchange.Route.from(envelope, provider, denied, .{});
    try std.testing.expect(!denied_route.capsule_restore_allowed);
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.restoreFromRequestEnvelopeWithCapability(&restore_runtime, .{}, envelope, denied_route, provider, denied, .{}));

    var broad = try Program.Exchange.Capability.encode(std.testing.allocator, .{
        .issuer_label = "host",
        .provider_fingerprint = provider.provider_fingerprint,
        .manifest_fingerprint = manifest.fingerprint,
        .allowed_operation_sites = &[_]usize{envelope.site_index},
        .allow_capsule_restore = true,
        .max_capsule_image_bytes = envelope.capsule_image.?.len,
    });
    defer broad.deinit();
    var wrong_site_restore = broad;
    wrong_site_restore.allowed_operation_sites = &[_]usize{999};
    const wrong_site_route = Program.Exchange.Route.from(envelope, provider, wrong_site_restore, .{});
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.restoreFromRequestEnvelopeWithCapability(&restore_runtime, .{}, envelope, wrong_site_route, provider, wrong_site_restore, .{}));
    var provider_restore_denied = provider;
    provider_restore_denied.accepts_capsule_restore = false;
    const provider_denied_route = Program.Exchange.Route.from(envelope, provider_restore_denied, broad, .{});
    try std.testing.expect(!provider_denied_route.capsule_restore_allowed);
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.restoreFromRequestEnvelopeWithCapability(&restore_runtime, .{}, envelope, provider_denied_route, provider_restore_denied, broad, .{}));
    const policy_denied_route = Program.Exchange.Route.from(envelope, provider, broad, .{ .allow_capsule_restore = false });
    try std.testing.expect(!policy_denied_route.capsule_restore_allowed);
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.restoreFromRequestEnvelopeWithCapability(&restore_runtime, .{}, envelope, policy_denied_route, provider, broad, .{ .allow_capsule_restore = false }));

    const restore_route = Program.Exchange.Route.from(envelope, provider, broad, .{});
    try std.testing.expect(restore_route.valid());
    try std.testing.expect(restore_route.capsule_restore_allowed);
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.restoreFromRequestEnvelopeWithCapability(&restore_runtime, .{}, envelope, restore_route, provider_restore_denied, broad, .{}));
    var restored = try Program.Exchange.restoreFromRequestEnvelopeWithCapability(&restore_runtime, .{}, envelope, restore_route, provider, broad, .{});
    defer restored.deinit();
    try std.testing.expectEqual(envelope.request_fingerprint, switch (try restored.current()) {
        .request => |current| current.fingerprint(),
        .after => return error.UnexpectedAfter,
        .none => return error.ExpectedRequest,
    });
}

test "Program.Exchange response envelope applies to parked transform request" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.transform, "exchange-apply");
    };
    const Program = boundary.program("exchange-apply", struct {}, Body);
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();

    const request = switch (try session.next()) {
        .request => |value| value,
        .after => return error.UnexpectedAfter,
        .done => return error.UnexpectedDone,
    };
    var envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{});
    defer envelope.deinit();
    var response = try Program.Exchange.ResponseEnvelope.@"resume"(std.testing.allocator, envelope, @as(i32, 42));
    defer response.deinit();
    var decoded_response = try Program.Exchange.ResponseEnvelope.decode(std.testing.allocator, response.bytes);
    defer decoded_response.deinit();
    try decoded_response.validateForRequest(envelope);

    var other_response = try Program.Exchange.ResponseEnvelope.@"resume"(std.testing.allocator, envelope, @as(i32, 7));
    defer other_response.deinit();
    var forged_response_fields = decoded_response;
    forged_response_fields.value_image = other_response.value_image;
    forged_response_fields.response_value_fingerprint = other_response.response_value_fingerprint;
    forged_response_fields.response_trace_fingerprint = other_response.response_trace_fingerprint;
    try std.testing.expectError(error.ProgramContractViolation, forged_response_fields.validateForRequest(envelope));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.applyResponse(&session, forged_response_fields, .{}));

    var corrupt_response_bytes = decoded_response;
    corrupt_response_bytes.bytes = try std.testing.allocator.dupe(u8, decoded_response.bytes);
    defer std.testing.allocator.free(corrupt_response_bytes.bytes);
    corrupt_response_bytes.bytes[corrupt_response_bytes.bytes.len - 9] ^= 1;
    try std.testing.expectError(error.ProgramContractViolation, corrupt_response_bytes.validateForRequest(envelope));

    try Program.Exchange.applyResponse(&session, decoded_response, .{});

    var result = switch (try session.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };
    defer result.deinit();
    try std.testing.expectEqual(@as(i32, 42), result.value);
}

test "Program.Exchange after envelope applies through resume_after" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const StackedHandlers = struct {
        outer: struct {
            pub fn dispatch(_: *const @This()) !i32 {
                return 1;
            }

            pub fn afterDispatch(_: *const @This(), value: bool) ![]const u8 {
                return if (value) "outer:true" else "outer:false";
            }
        },
        inner: struct {
            pub fn dispatch(_: *const @This()) !i32 {
                return 7;
            }

            pub fn afterDispatch(_: *const @This(), value: i32) !bool {
                return value == 7;
            }
        },
    };
    const Body = struct {
        pub const compiled_plan = stackedAfterPlan("exchange-after");
    };
    const Program = boundary.program("exchange-after", StackedHandlers, Body);
    var session = try Program.Session.start(&runtime, .{ .outer = .{}, .inner = .{} });
    defer session.deinit();

    const outer_request = switch (try session.next()) {
        .request => |request| request,
        .done => return error.ExpectedRequest,
        .after => return error.UnexpectedAfter,
    };
    try session.resumeTyped(try outer_request.as(Program.protocol.operationSite("outer", "outer", 0)), @as(i32, 1));
    const inner_request = switch (try session.next()) {
        .request => |request| request,
        .done => return error.ExpectedRequest,
        .after => return error.UnexpectedAfter,
    };
    try session.resumeTyped(try inner_request.as(Program.protocol.operationSite("inner", "inner", 0)), @as(i32, 7));

    const inner_after = switch (try session.next()) {
        .after => |after| after,
        .request => return error.ExpectedAfter,
        .done => return error.ExpectedAfter,
    };
    var envelope = try Program.Exchange.RequestEnvelope.fromAfter(std.testing.allocator, inner_after, .{});
    defer envelope.deinit();
    var response = try Program.Exchange.ResponseEnvelope.resumeAfter(std.testing.allocator, envelope, true);
    defer response.deinit();
    try Program.Exchange.applyResponse(&session, response, .{});

    const outer_after = switch (try session.next()) {
        .after => |after| after,
        .request => return error.ExpectedAfter,
        .done => return error.ExpectedAfter,
    };
    try session.resumeAfterTyped(try outer_after.as(Program.protocol.afterSite("outer", "outer", 0)), @as([]const u8, "outer:true"));
    var result = switch (try session.next()) {
        .done => |done| done,
        .request => return error.ExpectedDone,
        .after => return error.UnexpectedAfter,
    };
    defer result.deinit();
    try std.testing.expectEqualStrings("outer:true", result.value);
}

test "Program.Exchange policy rejects capsules and disallowed response kinds" {
    var runtime = boundary.Runtime.init(std.testing.allocator);
    defer runtime.deinit();

    const Body = struct {
        pub const compiled_plan = sessionStringOpPlan(.choice, "exchange-policy");
    };
    const Program = boundary.program("exchange-policy", struct {}, Body);
    var session = try Program.Session.start(&runtime, .{});
    defer session.deinit();
    const request = switch (try session.next()) {
        .request => |value| value,
        .after => return error.UnexpectedAfter,
        .done => return error.UnexpectedDone,
    };
    var capsule = try session.capture(std.testing.allocator);
    defer capsule.deinit();
    var image = try capsule.encode(std.testing.allocator);
    defer image.deinit();
    var envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{ .capsule = image });
    defer envelope.deinit();
    var plain_envelope = try Program.Exchange.RequestEnvelope.fromRequest(std.testing.allocator, request, .{});
    defer plain_envelope.deinit();

    try std.testing.expectError(error.ProgramContractViolation, (Program.Exchange.Policy{ .allow_capsules = false }).validateRequest(envelope));
    try std.testing.expectError(error.ProgramContractViolation, (Program.Exchange.Policy{ .branch_policy = .no_branch }).validateRequest(plain_envelope));
    try std.testing.expectError(error.ProgramContractViolation, (Program.Exchange.Policy{ .replay_policy = .replayed }).validateRequest(plain_envelope));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, plain_envelope.bytes, .{
        .usage = .linear,
    }));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, plain_envelope.bytes, .{
        .branch_policy = .no_branch,
    }));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, envelope.bytes, .{
        .allow_capsules = false,
    }));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, envelope.bytes, .{
        .max_envelope_bytes = envelope.bytes.len - 1,
    }));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, envelope.bytes, .{
        .max_payload_bytes = envelope.value_image.len - 1,
    }));
    if (envelope.capsule_image) |capsule_bytes| {
        try std.testing.expect(capsule_bytes.len > envelope.value_image.len);
        try std.testing.expectError(error.ProgramContractViolation, (Program.Exchange.Policy{
            .max_payload_bytes = envelope.value_image.len,
        }).validateRequest(envelope));
        try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, envelope.bytes, .{
            .max_payload_bytes = envelope.value_image.len,
            .max_capsule_image_bytes = capsule_bytes.len - 1,
        }));
        var decoded_capsule_policy = try Program.Exchange.RequestEnvelope.decodeWithPolicy(std.testing.allocator, envelope.bytes, .{
            .max_payload_bytes = envelope.value_image.len,
            .max_capsule_image_bytes = capsule_bytes.len,
        });
        defer decoded_capsule_policy.deinit();
        try std.testing.expectEqual(envelope.fingerprint, decoded_capsule_policy.fingerprint);
    } else return error.ExpectedCapsule;

    var response = try Program.Exchange.ResponseEnvelope.returnNow(std.testing.allocator, envelope, @as(i32, 9));
    defer response.deinit();
    try std.testing.expectError(error.ProgramContractViolation, (Program.Exchange.Policy{
        .allowed_response_kinds = .{ .return_now = false },
    }).validateResponse(response));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.ResponseEnvelope.decodeWithPolicy(std.testing.allocator, response.bytes, .{
        .allowed_response_kinds = .{ .return_now = false },
    }));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.ResponseEnvelope.decodeWithPolicy(std.testing.allocator, response.bytes, .{
        .allow_response_value_images = false,
    }));
    try std.testing.expectError(error.ProgramContractViolation, Program.Exchange.ResponseEnvelope.decodeWithPolicy(std.testing.allocator, response.bytes, .{
        .max_payload_bytes = response.value_image.len - 1,
    }));
}

